import java.util.*;

public class Solution {

    // Helper class for Dijkstra's priority queue elements
    static class State {
        long heavyCount;
        int node;

        public State(long heavyCount, int node) {
            this.heavyCount = heavyCount;
            this.node = node;
        }
    }

    /**
     * Checks if a path exists from source to target using at most k heavy edges 
     * when the threshold is T.
     */
    private static boolean canReach(int n, long[][] edges, int source, int target, long k, long T) {
        if (source == target) return true;

        // 1. Build Adjacency List based on T
        // Adj[u] stores pairs (v, weight)
        List<List<int[]>> adj = new ArrayList<>();
        for (int i = 0; i < n; i++) {
            adj.add(new ArrayList<>());
        }

        for (long[] edge : edges) {
            int u = (int) edge[0];
            int v = (int) edge[1];
            long w = edge[2];

            // Cost is 1 if heavy (w > T), 0 if light (w <= T)
            int cost = (w > T) ? 1 : 0;

            // Store neighbor and cost
            adj.get(u).add(new int[]{v, cost});
            adj.get(v).add(new int[]{u, cost});
        }

        // 2. Dijkstra's Algorithm
        // dist[i] stores the minimum number of heavy edges to reach node i
        long[] dist = new long[n];
        Arrays.fill(dist, Long.MAX_VALUE);

        // Priority Queue stores (heavyCount, node), prioritizing minimum heavyCount
        PriorityQueue<State> pq = new PriorityQueue<>(Comparator.comparingLong(s -> s.heavyCount));

        dist[source] = 0;
        pq.add(new State(0, source));

        while (!pq.isEmpty()) {
            State current = pq.poll();
            long h = current.heavyCount;
            int u = current.node;

            if (h > dist[u]) {
                continue;
            }

            if (u == target) {
                // We found the minimum heavy path, check against k
                return h <= k;
            }

            for (int[] neighborData : adj.get(u)) {
                int v = neighborData[0];
                int cost = neighborData[1]; // 0 or 1

                long newHeavyCount = h + cost;

                if (newHeavyCount < dist[v]) {
                    dist[v] = newHeavyCount;
                    pq.add(new State(newHeavyCount, v));
                }
            }
        }

        // If the loop finishes and we haven't returned, the target was unreachable 
        // or the minimum heavy count was > k.
        return dist[target] <= k;
    }


    public static long solve(long n_long, long[][] edges, long source_long, long target_long, long k_long) {
        // Cast inputs to int/long as appropriate based on constraints (N<=1000)
        int n = (int) n_long;
        int source = (int) source_long;
        int target = (int) target_long;
        long k = k_long;

        if (source == target) {
            return 0;
        }

        // 1. Identify Search Space for Threshold T
        // Weights are up to 10^9. We search T in [0, 10^9 + 1]
        long L = 0;
        // R must be large enough to test the case where the threshold needs to be >= max weight.
        // If max weight is 10^9, T=10^9 makes all edges light.
        long R = 1_000_000_000L + 1; 

        long min_T = -1;

        // 2. Binary Search on T
        while (L <= R) {
            long M = L + (R - L) / 2;

            if (canReach(n, edges, source, target, k, M)) {
                // Threshold M works. Store it, and try for a smaller threshold.
                min_T = M;
                R = M - 1;
            } else {
                // Threshold M does not work. We need a higher threshold to classify more edges as light.
                L = M + 1;
            }
        }

        return min_T;
    }
}
