import java.util.*;

public class Solution {

    // Helper class for Dijkstra's Priority Queue
    static class State implements Comparable<State> {
        int node;
        int heavyCount;

        public State(int node, int heavyCount) {
            this.node = node;
            this.heavyCount = heavyCount;
        }

        @Override
        public int compareTo(State other) {
            // Prioritize lower heavyCount
            return Integer.compare(this.heavyCount, other.heavyCount);
        }
    }

    // Helper class to store edge information
    static class EdgeInfo {
        int to;
        long weight;

        public EdgeInfo(int to, long weight) {
            this.to = to;
            this.weight = weight;
        }
    }

    /**
     * Checks if a path exists from source to target using at most k heavy edges,
     * given the threshold T.
     * Uses Dijkstra's algorithm where edge weights are 0 (light) or 1 (heavy).
     */
    private boolean check(long T, int N, List<EdgeInfo>[] adj, int source, int target, int K) {
        if (source == target) return true;

        // D[i] stores the minimum number of heavy edges required to reach node i
        int[] D = new int[N];
        Arrays.fill(D, Integer.MAX_VALUE);

        PriorityQueue<State> pq = new PriorityQueue<>();

        D[source] = 0;
        pq.add(new State(source, 0));

        while (!pq.isEmpty()) {
            State current = pq.poll();
            int u = current.node;
            int currentHeavyCount = current.heavyCount;

            if (currentHeavyCount > D[u]) {
                continue;
            }

            if (u == target) {
                // Since Dijkstra finds the minimum, if we reach target, we check the constraint K
                return currentHeavyCount <= K;
            }

            for (EdgeInfo edge : adj[u]) {
                int v = edge.to;
                long W = edge.weight;

                // Determine cost (0 if light, 1 if heavy)
                int cost = (W > T) ? 1 : 0;

                int newHeavyCount = currentHeavyCount + cost;

                if (newHeavyCount <= K && newHeavyCount < D[v]) {
                    D[v] = newHeavyCount;
                    pq.add(new State(v, newHeavyCount));
                }
            }
        }

        // If target was never reached or the minimum count exceeded K
        return D[target] <= K;
    }


    public static long solve(long nLong, long[][] edges, long sourceLong, long targetLong, long kLong) {
        int N = (int) nLong;
        int source = (int) sourceLong;
        int target = (int) targetLong;
        int K = (int) kLong;

        if (source == target) {
            return 0;
        }

        // 1. Build Graph
        List<EdgeInfo>[] adj = new List[N];
        for (int i = 0; i < N; i++) {
            adj[i] = new ArrayList<>();
        }

        // Store all unique weights to define the search space, though we can binary search over [0, 10^9 + 1]
        long maxWeight = 0;
        for (long[] edge : edges) {
            int u = (int) edge[0];
            int v = (int) edge[1];
            long w = edge[2];

            adj[u].add(new EdgeInfo(v, w));
            adj[v].add(new EdgeInfo(u, w));

            if (w > maxWeight) {
                maxWeight = w;
            }
        }

        // 2. Binary Search for the minimum threshold T
        // Search space: [L, R]. L=0 (minimum possible threshold). R = maxWeight + 1 (guarantees all edges are light).
        long L = 0;
        long R = maxWeight + 1; 
        long ans = -1;

        while (L <= R) {
            long M = L + (R - L) / 2;

            if (check(M, N, adj, source, target, K)) {
                // M works, try for a smaller threshold
                ans = M;
                R = M - 1;
            } else {
                // M is too small, need a larger threshold
                L = M + 1;
            }
        }

        return ans;
    }
}

