import java.util.ArrayList;
import java.util.Arrays;
import java.util.Deque;
import java.util.LinkedList;
import java.util.List;

public class Solution {

    // Helper class to represent an edge in the adjacency list
    static class Edge {
        int to;
        long weight;
        Edge(int to, long weight) {
            this.to = to;
            this.weight = weight;
        }
    }

    // Helper class for 0/1 BFS state
    static class State {
        int node;
        int heavyCount;
        State(int node, int heavyCount) {
            this.node = node;
            this.heavyCount = heavyCount;
        }
    }

    /**
     * Checks if a valid path exists from source to target using at most K heavy edges 
     * given the current threshold. Uses 0/1 BFS.
     * N is cast from long n input. K is cast from long k input.
     */
    private static boolean check(long threshold, int N, List<Edge>[] adj, int source, int target, int K) {
        // D[u] stores the minimum heavy edge count to reach u
        int[] D = new int[N];
        Arrays.fill(D, Integer.MAX_VALUE);

        Deque<State> deque = new LinkedList<>();

        D[source] = 0;
        deque.addFirst(new State(source, 0));

        while (!deque.isEmpty()) {
            State current = deque.pollFirst();
            int u = current.node;
            int h = current.heavyCount;

            if (h > D[u]) {
                continue;
            }

            if (h > K) {
                 // Optimization: If we reached here, it means h <= K must hold 
                 // because we only push states with h <= K+1 potentially, 
                 // but if h itself exceeds K, we stop expansion from this state.
                 continue; 
            }

            for (Edge edge : adj[u]) {
                int v = edge.to;
                long w = edge.weight;

                // Edge is heavy if weight > threshold
                int cost = (w > threshold) ? 1 : 0;
                int h_new = h + cost;

                if (h_new < D[v]) {
                    D[v] = h_new;
                    State next = new State(v, h_new);

                    if (cost == 0) {
                        // Light edge (cost 0) goes to the front
                        deque.addFirst(next);
                    } else { 
                        // Heavy edge (cost 1) goes to the back
                        deque.addLast(next);
                    }
                }
            }
        }

        return D[target] <= K;
    }

    public static long solve(long n, long[][] edges, long source, long target, long k) {
        int N = (int) n;
        int S = (int) source;
        int T = (int) target;
        int K = (int) k;

        // 1. Build Adjacency List
        List<Edge>[] adj = new List[N];
        for (int i = 0; i < N; i++) {
            adj[i] = new ArrayList<>();
        }

        long maxWeight = 0;
        for (long[] edge : edges) {
            int u = (int) edge[0];
            int v = (int) edge[1];
            long w = edge[2];
            adj[u].add(new Edge(v, w));
            adj[v].add(new Edge(u, w));
            if (w > maxWeight) {
                maxWeight = w;
            }
        }

        // Handle trivial case: source == target
        if (S == T) {
            return 0;
        }

        // 2. Binary Search setup
        // Search space for threshold T: [0, maxWeight]
        // If maxWeight is 0 (only possible if edges is empty, but weights >= 1), 
        // the range [0, 0] is fine. If weights are up to 10^9, we search up to 10^9.

        long low = 0;
        // We use maxWeight + 1 as the upper bound R because a threshold T=maxWeight 
        // means all edges are light (since weight <= threshold). If T=maxWeight+1, 
        // it's the same. We set R slightly above the max possible weight.
        long high = maxWeight + 1; 
        long result = -1;

        // 3. Binary Search
        while (low <= high) {
            long mid = low + (high - low) / 2;

            if (check(mid, N, adj, S, T, K)) {
                // Threshold 'mid' works. Try for a smaller threshold.
                result = mid;
                high = mid - 1;
            } else {
                // Threshold 'mid' is too small (too many heavy edges). Increase threshold.
                low = mid + 1;
            }
        }

        return result;
    }
}
