     * given the current threshold. Uses 0/1 BFS.
     * N is cast from long n input. K is cast from long k input.
     */
    private static boolean check(long threshold, int N, List<Edge>[] adj, int source, int target, int K) {
        // D[u] stores the minimum heavy edge count to reach u
        int[] D = new int[N];
        Arrays.fill(D, Integer.MAX_VALUE);

        Deque<State> deque = new LinkedList<>();

        D[source] = 0;
        deque.addFirst(new State(source, 0));

        while (!deque.isEmpty()) {
            State current = deque.pollFirst();
            int u = current.node;
            int h = current.heavyCount;

            if (h > D[u]) {
                continue;
            }

            if (h > K) {
                 // Optimization: If we reached here, it means h <= K must hold 
                 // because we only push states with h <= K+1 potentially, 
                 // but if h itself exceeds K, we stop expansion from this state.
                 continue; 
            }

            for (Edge edge : adj[u]) {
                int v = edge.to;
                long w = edge.weight;

                // Edge is heavy if weight > threshold
                int cost = (w > threshold) ? 1 : 0;
                int h_new = h + cost;

                if (h_new < D[v]) {
                    D[v] = h_new;
                    State next = new State(v, h_new);

                    if (cost == 0) {
                        // Light edge (cost 0) goes to the front
                        deque.addFirst(next);
                    } else { 
                        // Heavy edge (cost 1) goes to the back
                        deque.addLast(next);
                    }
                }
            }
        }

        return D[target] <= K;
    }

    public static long solve(long n, long[][] edges, long source, long target, long k) {
        int N = (int) n;
        int S = (int) source;
        int T = (int) target;
        int K = (int) k;

        // 1. Build Adjacency List
        List<Edge>[] adj = new List[N];
        for (int i = 0; i < N; i++) {
            adj[i] = new ArrayList<>();
        }

        long maxWeight = 0;
        for (long[] edge : edges) {
            int u = (int) edge[0];
            int v = (int) edge[1];
            long w = edge[2];
            adj[u].add(new Edge(v, w));
