            return 0;
        }

        // 2. Binary Search setup
        // Search space for threshold T: [0, maxWeight]
        // If maxWeight is 0 (only possible if edges is empty, but weights >= 1), 
        // the range [0, 0] is fine. If weights are up to 10^9, we search up to 10^9.

        long low = 0;
        // We use maxWeight + 1 as the upper bound R because a threshold T=maxWeight 
        // means all edges are light (since weight <= threshold). If T=maxWeight+1, 
        // it's the same. We set R slightly above the max possible weight.
        long high = maxWeight + 1; 
        long result = -1;

        // 3. Binary Search
        while (low <= high) {
            long mid = low + (high - low) / 2;

            if (check(mid, N, adj, S, T, K)) {
